    let maxSum = 0;
    const n = nums.length;

    // Iterate all possible masks for A and B (each bit represents if the element is in A or B)
    // Since each element can be in A, B, or C, we need to represent 3 states per element.
    // However, with n up to 19, 3^19 is too large (1.16e9), so we need a smarter approach.
    // Instead, we can iterate all possible non-empty B and compute XOR(A) + AND(B) + XOR(C)
    // where A and C are formed by the remaining elements.

    // The key observation is that the optimal solution will have B as a contiguous AND sequence
    // but this might not always be true. Given the constraints (n <=19), we can afford O(2^n) or O(3^n)

    // We'll try all possible subsets for B, then the remaining elements can be split into A and C in any way.
    // For each B, the optimal split of remaining elements into A and C is to maximize XOR(A) + XOR(C)
    // This is equivalent to splitting the remaining elements into two parts where their XOR sum is maximized.
    // The maximum XOR of two parts is the total XOR of all elements (since a ^ b = total_xor, and a + b = a + (total_xor ^ a))
    // So the maximum is when one part is the total_xor and the other is 0, sum is total_xor.
    // So for a given B, the maximum XOR(A) + XOR(C) is xor_rest, where xor_rest is XOR of all elements not in B.

    // So the approach is:
    // For every possible non-empty B, compute AND(B) + xor_rest (xor_rest is XOR of all elements not in B)
    // Also consider the case where B is empty, then the sum is XOR(A) + XOR(C), which is the total XOR (since C is the rest)
    // But total XOR can be split into any a + b where a ^ b = total_xor. The maximum a + b is when a is total_xor and b is 0 (sum is total_xor)
    // So the maximum when B is empty is total_xor.

    const totalXor = nums.reduce((acc, num) => acc ^ num, 0);
    maxSum = totalXor; // case when B is empty

    // Generate all possible non-empty subsets of nums for B
    for (let mask = 1; mask < (1 << n); mask++) {
        let andB = ~0; // all bits set for AND
        let xorRest = 0;
        for (let i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                andB &= nums[i];
            } else {
                xorRest ^= nums[i];
            }
        }
        const currentSum = andB + xorRest;
        if (currentSum > maxSum) {
            maxSum = currentSum;
        }
    }

    return maxSum;
}

